code.imports:
import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { Avatar, Badge, Card, icon } from 'decantr/components';

code.example:
function Leaderboard({ entries }) {
  const { div, span, h3 } = tags;
  const top3 = entries.slice(0, 3);
  const rest = entries.slice(3);
  const medals = ['trophy', 'medal', 'award'];

  return div({ class: css('_flex _col _gap4') },
    div({ class: css('_flex _aic _jcsb') },
      h3({ class: css('_heading4') }, 'Leaderboard'),
      Badge({ variant: 'outline' }, 'This Season')
    ),
    div({ class: css('_grid _gc3 _gap3 _aic') },
      ...([top3[1], top3[0], top3[2]].filter(Boolean).map((entry, i) => {
        const isFirst = i === 1;
        return Card({ class: css(`_tc ${isFirst ? '_py6' : '_py4'}`) },
          Card.Body({ class: css('_flex _col _aic _gap2') },
            Avatar({ src: entry.avatar, size: isFirst ? 'lg' : 'md' }),
            span({ class: css('_medium _textsm') }, entry.name),
            span({ class: css('_textxs _fgmuted') }, entry.stat),
            Badge({ variant: isFirst ? 'primary' : 'outline' },
              icon(medals[isFirst ? 0 : i === 0 ? 1 : 2], { size: '0.75rem' }),
              ` #${isFirst ? 1 : i === 0 ? 2 : 3}`
            )
          )
        );
      }))
    ),
    div({ class: css('_flex _col _gap1') },
      ...rest.map((entry, i) =>
        div({ class: css('_flex _aic _gap3 _py2 _px3 _borderB') },
          span({ class: css('_w6 _tc _textxs _fgmuted') }, `${i + 4}`),
          Avatar({ src: entry.avatar, size: 'sm' }),
          span({ class: css('_flex1 _textsm _medium') }, entry.name),
          span({ class: css('_textsm _fgmuted') }, entry.stat),
          Badge({ variant: 'outline', size: 'sm' }, entry.rank)
        )
      )
    )
  );
}

