code.example:
function SpotlightLeaderboard({ entries }) {
  const { div, span, h4 } = tags;
  const top3 = entries.slice(0, 3);
  const rankColors = ['_fgprimary', '_fgaccent', '_fgwarning'];

  return div({ class: css('_flex _col _gap2') },
    div({ class: css('_flex _aic _jcsb') },
      h4({ class: css('_textsm _medium') }, 'Top Players'),
      Badge({ variant: 'outline', size: 'sm' }, 'This Week')
    ),
    ...top3.map((entry, i) =>
      div({ class: css('_flex _aic _gap2 _py1') },
        span({ class: css(`_w4 _tc _textxs _medium ${rankColors[i]}`) }, `#${i + 1}`),
        Avatar({ src: entry.avatar, size: 'xs' }),
        span({ class: css('_flex1 _textsm') }, entry.name),
        span({ class: css('_textsm _fgmuted') }, entry.stat)
      )
    )
  );
}

